"""
Clean test case for nested blocks with multiple overrides at different levels
"""
import os, sys, tempfile, shutil
sys.path.insert(0, '/workspace')

import django
from django.conf import settings

if not settings.configured:
    settings.configure(DEBUG=True, INSTALLED_APPS=[], TEMPLATES=[{
        'BACKEND': 'django.template.backends.django.DjangoTemplates',
        'DIRS': [], 'APP_DIRS': False, 'OPTIONS': {'context_processors': []},
    }])
    django.setup()

from django.template.loader import get_template
from django.test.utils import override_settings

tests = [
    {
        'name': 'Test 1: Nested blocks with all levels overriding both',
        'templates': {
            'base.html': 'A{% block outer %}B{% block inner %}C{% endblock %}D{% endblock %}E',
            'middle.html': "{% extends 'base.html' %}{% block outer %}B2{% block inner %}C2{% endblock %}D2{% endblock %}",
            'inner.html': "{% extends 'middle.html' %}{% block inner %}C3{% endblock %}",
        },
        'render': 'inner.html',
        'expected': 'AB2C3D2E',
    },
    {
        'name': 'Test 2: Same as Test 1 but explicit',
        'templates': {
            'base.html': 'A{% block outer %}B{% block inner %}C{% endblock %}D{% endblock %}E',
            'middle.html': "{% extends 'base.html' %}{% block outer %}B2{% block inner %}C2{% endblock %}D2{% endblock %}",
            'inner.html': "{% extends 'middle.html' %}{% block inner %}C3{% endblock %}",
        },
        'render': 'inner.html',
        'expected': 'AB2C3D2E',
    },
    {
        'name': 'Test 3: Inner extends middle WITH NO OVERRIDES',
        'templates': {
            'base.html': 'A{% block outer %}B{% block inner %}C{% endblock %}D{% endblock %}E',
            'middle.html': "{% extends 'base.html' %}{% block outer %}B2{% block inner %}C2{% endblock %}D2{% endblock %}",
            'inner.html': "{% extends 'middle.html' %}",
        },
        'render': 'inner.html',
        'expected': 'AB2C2D2E',
    },
    {
        'name': 'Test 4: Base -> Middle -> Inner (4 levels)',
        'templates': {
            'base.html': 'X{% block a %}1{% block b %}2{% endblock %}3{% endblock %}Y',
            'mid1.html': "{% extends 'base.html' %}{% block a %}1M1{% block b %}2M1{% endblock %}3M1{% endblock %}",
            'mid2.html': "{% extends 'mid1.html' %}{% block b %}2M2{% endblock %}",
            'inner.html': "{% extends 'mid2.html' %}{% block b %}2I{% endblock %}",
        },
        'render': 'inner.html',
        'expected': 'X1M13M1Y',  # Wait, this should use mid2's block...
    },
]

for i, test in enumerate(tests):
    print(f"\n{test['name']}")
    print("-" * 70)

    # Create a separate temp dir for this test
    test_temp_dir = tempfile.mkdtemp()
    try:
        # Create template files
        for name, content in test['templates'].items():
            with open(os.path.join(test_temp_dir, name), 'w') as f:
                f.write(content)

        with override_settings(TEMPLATES=[{
            'BACKEND': 'django.template.backends.django.DjangoTemplates',
            'DIRS': [test_temp_dir],
            'APP_DIRS': False,
            'OPTIONS': {'context_processors': []},
        }]):
            try:
                tmpl = get_template(test['render'])
                output = tmpl.render({})
                expected = test['expected']

                print(f"  Expected: {expected}")
                print(f"  Got:      {output}")
                if output == expected:
                    print("  ✓ PASS")
                else:
                    print("  ✗ FAIL")
            except Exception as e:
                print(f"  ✗ ERROR: {e}")
                import traceback
                traceback.print_exc()
    finally:
        shutil.rmtree(test_temp_dir, ignore_errors=True)

